import { useEffect, useState } from "react";
import axios from "axios";

// 🔹 Config: Define all tables with headers + keys
const tablesConfig = [
    {
        title: "Temp DNC Leads",
        key: "tbltemp_dncleads_tracker",
        headers: ["First", "Last", "Email", "Phone", "Company", "Domain", "Campaign", "Date", "Followed By"],
        fields: ["first_name", "last_name", "email", "phone", "company", "domain", "campaign", "date", "followed_by"],
    },
    {
        title: "SMTP Audit Tracker V3",
        key: "tblsmtpaudit_details_tracker_v3",
        headers: ["Track ID", "Record ID", "I Date", "Client ID", "Email ID", "Reason Code", "Tool1 ID", "Tool1 Status", "SMTP1 Result", "SMTP1 Dt", "Final Status", "Uploaded By"],
        fields: ["Track_id", "Record_id", "iDate", "Client_id", "Email_id", "Reason_code", "Tool1_id", "Tool1_status", "SMTP1_result", "SMTP1_dt", "Final_status", "Uploaded_by"],
    },
    {
        title: "SMTP Audit V3",
        key: "tblsmtpaudit_details_v3",
        headers: ["Record ID", "I Date", "Client ID", "Email ID", "Reason Code", "Tool1 ID", "Tool1 Status", "SMTP1 Result", "SMTP1 Dt", "Final Status", "Uploaded By"],
        fields: ["Record_id", "iDate", "Client_id", "Email_id", "Reason_code", "Tool1_id", "Tool1_status", "SMTP1_result", "SMTP1_dt", "Final_status", "Uploaded_by"],
    },
    {
        title: "Masterlist",
        key: "tblleads_masterlist_tracker",
        headers: ["Track ID", "Email ID", "Lead ID", "Company Name", "Industry", "Phone Number", "Mobile No", "Job Title", "First Name", "Last Name"],
        fields: ["Track_id", "Email_id", "Lead_id", "Company_name", "Industry", "Phone_number", "Mobile_No", "Job_title", "First_name", "Last_name"],
    },
];

// 🔹 Reusable Table Component
const DataTable = ({ title, headers, rows, fields }) => (
    <div className="card mb-4 shadow-sm border-0">
        <div className="card-header bg-primary text-white fw-bold">{title}</div>
        <div className="card-body p-0">
            <div className="table-responsive">
                {rows?.length > 0 ? (
                    <table className="table table-hover table-bordered align-middle mb-0">
                        <thead className="table-light">
                            <tr>{headers.map((h, i) => <th key={i}>{h}</th>)}</tr>
                        </thead>
                        <tbody>
                            {rows.map((row, i) => (
                                <tr key={i}>
                                    {fields.map((f, j) => (
                                        <td key={j}>
                                            {row[f] ? (
                                                <span className="text-dark">{row[f]}</span>
                                            ) : (
                                                <span className="badge bg-secondary">N/A</span>
                                            )}
                                        </td>
                                    ))}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                ) : (
                    <p className="text-muted text-center m-3">No records found</p>
                )}
            </div>
        </div>
    </div>
);

function Leads() {
    const [data, setData] = useState({});
    const [selectedRole, setSelectedRole] = useState("super_admin");
    const [showDecrypted, setShowDecrypted] = useState(false);

    useEffect(() => {
        const fetchLeads = async () => {
            try {
                const res = await axios.get("http://172.16.60.17:8000/leads", {
                    params: { role: selectedRole, decrypted: showDecrypted ? 1 : 0 },
                });
                setData(res.data);
            } catch (error) {
                console.error("Error fetching leads:", error);
                setData({});
            }
        };
        fetchLeads();
    }, [selectedRole, showDecrypted]);

    return (
        <div className="container py-4">
            {/* 🔹 Header */}
            <div className="d-flex justify-content-between align-items-center mb-4">
                <h2 className="fw-bold text-primary">📊 Leads Dashboard</h2>
                <div className="d-flex gap-2">
                    <select
                        className="form-select form-select-sm"
                        value={selectedRole}
                        onChange={(e) => setSelectedRole(e.target.value)}
                    >
                        <option value="super_admin">Super Admin</option>
                        <option value="admin">Admin</option>
                        <option value="agent">Agent</option>
                    </select>
                    <button
                        className={`btn btn-sm ${showDecrypted ? "btn-outline-danger" : "btn-outline-success"}`}
                        onClick={() => setShowDecrypted((prev) => !prev)}
                        disabled={selectedRole === "agent"}
                    >
                        {showDecrypted ? "🔒 Encrypted View" : "🔑 Decrypted View"}
                    </button>
                </div>
            </div>

            {/* 🔹 Tables */}
            {tablesConfig.map((tbl, i) => (
                <DataTable
                    key={i}
                    title={tbl.title}
                    headers={tbl.headers}
                    fields={tbl.fields}
                    rows={data[tbl.key]}
                />
            ))}
        </div>
    );
}

export default Leads;
